// Build Prompt â€” Agent 1: Resume Drafter
// All persona, style, and personalization rules live in system_prompt
// (loaded from Drive doc via Prompt Loader). This node only constructs
// the user_message with per-job context, and enforces the pipeline-level
// output contract (no header â€” the resume converter adds that from config).
// Mode: Run Once for Each Item
const input = $input.item.json;
// Job data (passed in via plan from Fan Out Plans)
const jobData = (input.job && typeof input.job === 'object' && !Array.isArray(input.job))
  ? input.job
  : input;
const company = jobData.company || '';
const title = jobData.title || '';
const location = jobData.location || '';
const url = jobData.url || '';
const descriptionHtml = jobData.description_html || '';
// Master career doc â€” source of truth for candidate facts
const masterDoc = input.master_doc || '';
// Config â€” provides positioning context (profile, target titles, domain)
let config = input.config;
if (typeof config === 'string' || !config || typeof config !== 'object') {
  console.log('[Build Prompt] config not an object â€” using defaults');
  config = {};
}
const profileSummary = config.profile_summary || '';
const targetTitles = config.target_titles || '';
const domainInterests = config.domain_interests || '';
// LLM routing
const provider = input.provider;
const model = input.model;
const maxTokens = input.max_tokens;
// System prompt loaded from Drive doc (passed in by orchestrator)
const systemPromptFromDoc = input.system_prompt || '';
// Validation
if (!systemPromptFromDoc || systemPromptFromDoc.length < 100) {
  throw new Error(`[Agent 1] system_prompt missing or too short (${systemPromptFromDoc.length} chars). Check Prompt Loader output and orchestrator mapping.`);
}
if (!masterDoc || masterDoc.length < 100) {
  throw new Error(`[Agent 1] master_doc empty/short (${masterDoc.length} chars)`);
}
if (!descriptionHtml || descriptionHtml.length < 30) {
  throw new Error(`[Agent 1] descriptionHtml empty/short (${descriptionHtml.length} chars)`);
}
console.log('[Build Prompt] company:', company);
console.log('[Build Prompt] systemPromptFromDoc length:', systemPromptFromDoc.length);
console.log('[Build Prompt] masterDoc length:', masterDoc.length);
console.log('[Build Prompt] descriptionHtml length:', descriptionHtml.length);
function cleanHTML(html) {
  return String(html)
    .replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n\n').replace(/<\/li>/gi, '\n').replace(/<li>/gi, '- ').replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ')
    .replace(/\n{3,}/g, '\n\n').trim();
}
const cleanJD = cleanHTML(descriptionHtml);
// Pipeline-level output contract â€” the only hardcoded rule here.
// The resume converter adds name/contact/Education/etc. downstream from config.
const OUTPUT_CONTRACT = `# OUTPUT CONTRACT (set by pipeline, do not override)

Do NOT include any of these in your output: name, contact info, Education, Credentials, Patents, Publications, Awards, or Skills section. The resume converter adds those downstream from the candidate's config.

Start your response with "# " (the tagline) â€” first character must be "#" with no leading whitespace. Return ONLY the resume markdown body. No preamble, no commentary, no closing notes.

## Professional Experience format

For each role, use this exact structure:

### Company Name | Role Title | Start Year â€“ End Year

*One-line scope summary tailored to the target role. No metrics, no bullets.*

- First bullet (4-6 per role, action verb start, quantified where possible)
- Second bullet
- Third bullet

Role header line must:
- Start with \`### \` (the h3 marker â€” required for proper styling)
- Use \` | \` (space-pipe-space) as the separator between company, title, and years
- Use \` â€“ \` (en-dash with spaces) between start and end years
- Contain NO bold or italic markdown â€” the renderer adds styling

The scope line directly under the role header must:
- Be wrapped in \`*...*\` for italic
- Be one line, no wrapping
- Describe the role's scope (what kind of work, what domain)
- Contain NO metrics â€” those belong in bullets
- Have NO bullet marker (\`-\` or \`*\`)`;
const system = systemPromptFromDoc + '\n\n' + OUTPUT_CONTRACT;
const userMessage = `Tailor a resume for this specific job application.

# CANDIDATE'S MASTER CAREER DOCUMENT
This is the ONLY source of truth for candidate facts. Do not fabricate any experience, metric, date, technology, or skill not stated below.

${masterDoc}

# TARGET JOB
Company: ${company}
Title: ${title}
${location ? `Location: ${location}\n` : ''}${url ? `URL: ${url}\n` : ''}
# FULL JOB DESCRIPTION
${cleanJD}

# CANDIDATE POSITIONING CONTEXT
Profile summary anchor: ${profileSummary || '(derive from master document)'}
Target title categories: ${targetTitles || '(derive from master document)'}
Domain interests: ${domainInterests || '(derive from master document)'}`;
console.log(`[Build Prompt] Final system: ${system.length} chars, user: ${userMessage.length} chars`);
return {
  json: {
    provider,
    model,
    system,
    user_message: userMessage,
    max_tokens: maxTokens,
    prompt_chars: system.length + userMessage.length
  }
};

// Agent 1: format output as standard envelope
// Mode: Run Once for All Items
// Propagates structured error from Call LLM on failure.

const llmResponse = $input.first().json;

// Call LLM failed â€” propagate error without quality checks on empty content
if (llmResponse.success === false) {
  console.log(`[Agent 1] LLM call failed: ${llmResponse.error?.category || 'unknown'} â€” ${llmResponse.error?.message || 'no message'}`);
  return [{
    json: {
      success: false,
      result: { resume_markdown: '' },
      tokens: {
        input: llmResponse.input_tokens || 0,
        output: llmResponse.output_tokens || 0
      },
      cached_input_tokens: llmResponse.cached_input_tokens || 0,
      cache_write_tokens: llmResponse.cache_write_tokens || 0,
      model_used: llmResponse.model_used || 'unknown',
      provider_used: llmResponse.provider_used || 'unknown',
      errors: [...(llmResponse.errors || [])],
      error: llmResponse.error || {
        category: 'unknown',
        type: 'unknown',
        message: 'Call LLM returned success: false with no error object',
        provider: llmResponse.provider_used || 'unknown',
        model: llmResponse.model_used || 'unknown'
      }
    }
  }];
}

// Normal path: parse resume from content
const resumeMarkdown = (llmResponse.content || '')
  .trim()
  .replace(/^```(?:markdown|md)?\s*\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

const errors = [...(llmResponse.errors || [])];
let error = null;

if (resumeMarkdown.length <= 100) {
  errors.push('Resume output suspiciously short or empty');
  error = {
    category: 'output_quality',
    type: 'short_output',
    message: 'Resume output suspiciously short or empty',
    provider: llmResponse.provider_used || 'unknown',
    model: llmResponse.model_used || 'unknown'
  };
}

const success = resumeMarkdown.length > 100;

console.log(`[Agent 1] Output: ${resumeMarkdown.length} chars`);
console.log(`[Agent 1] Tokens: ${llmResponse.input_tokens || 0}in + ${llmResponse.output_tokens || 0}out + ${llmResponse.cached_input_tokens || 0}cached + ${llmResponse.cache_write_tokens || 0}cache_write`);
console.log(`[Agent 1] Provider/Model used: ${llmResponse.provider_used}/${llmResponse.model_used}`);

return [{
  json: {
    success,
    result: { resume_markdown: resumeMarkdown },
    tokens: {
      input: llmResponse.input_tokens || 0,
      output: llmResponse.output_tokens || 0
    },
    cached_input_tokens: llmResponse.cached_input_tokens || 0,
    cache_write_tokens: llmResponse.cache_write_tokens || 0,
    model_used: llmResponse.model_used || 'unknown',
    provider_used: llmResponse.provider_used || 'unknown',
    errors,
    error
  }
}];

// Set Inputs â€” Agent 1: Resume Builder
const trigger = $input.item.json;

function strip(val) {
  if (val === null || val === undefined) return '';
  if (typeof val !== 'string') return val;
  let cleaned = val;
  while (cleaned.length > 0 && cleaned.charAt(0) === '=') {
    cleaned = cleaned.substring(1);
  }
  return cleaned;
}

const config = trigger.config || {};
const systemPrompt = strip(trigger.system_prompt);
const company = strip(trigger.company);
const title = strip(trigger.title);
const descriptionHtml = strip(trigger.description_html);
const masterDoc = strip(trigger.master_doc);

const provider = strip(config.provider_resume_drafter);
if (!provider) {
  throw new Error('[Agent 1] config.provider_resume_drafter is required. Set it in your config sheet (anthropic | openai | gemini).');
}

const model = strip(config.model_resume_drafter);
if (!model) {
  throw new Error('[Agent 1] config.model_resume_drafter is required. Set it in your config sheet.');
}

const maxTokens = Number(config.max_tokens_resume_drafter);
if (!maxTokens || Number.isNaN(maxTokens)) {
  throw new Error('[Agent 1] config.max_tokens_resume_drafter is required and must be a number.');
}

console.log(`[Agent 1 Set Inputs] master_doc: ${masterDoc.length} chars, system_prompt: ${systemPrompt.length} chars, provider: ${provider}, model: ${model}`);

return {
  json: {
    config,
    system_prompt: systemPrompt,
    company,
    title,
    description_html: descriptionHtml,
    master_doc: masterDoc,
    provider,
    model,
    max_tokens: maxTokens
  }
};
